// REST Controller
@RestController
@RequestMapping("/api/v1/events")
class EventTrackingController {

    private final KafkaEventProducer kafkaEventProducer;

    public EventTrackingController(KafkaEventProducer kafkaEventProducer) {
        this.kafkaEventProducer = kafkaEventProducer;
    }

    @PostMapping("/publish")
    public ResponseEntity<EventResponse> publishEvent(
            @RequestBody EventRequest eventRequest,
            @RequestHeader(value = "X-Tracking-Id", required = false) String httpTrackingId,
            @RequestHeader(value = "X-User-Id", required = false) String httpUserId,
            @RequestHeader(value = "X-Correlation-Id", required = false) String correlationId,
            @RequestHeader(value = "X-Source-System", required = false) String sourceSystem) {

        EventResponse response = new EventResponse();

        try {
            // Validate required fields
            if (eventRequest.getTopic() == null || eventRequest.getTopic().isEmpty()) {
                response.setStatus("ERROR");
                response.setMessage("Topic is required");
                return ResponseEntity.badRequest().body(response);
            }

            if (eventRequest.getPayload() == null || eventRequest.getPayload().isEmpty()) {
                response.setStatus("ERROR");
                response.setMessage("Payload is required");
                return ResponseEntity.badRequest().body(response);
            }

            // Build headers map
            Map<String, String> kafkaHeaders = new HashMap<>();

            // Priority: body trackingId > HTTP header trackingId > auto-generated
            String trackingId = eventRequest.getTrackingId();
            if (trackingId == null || trackingId.isEmpty()) {
                trackingId = httpTrackingId;
            }
            if (trackingId == null || trackingId.isEmpty()) {
                trackingId = UUID.randomUUID().toString();
            }
            kafkaHeaders.put("tracking-id", trackingId);

            // User ID from body or HTTP header
            String userId = eventRequest.getUserId();
            if (userId == null || userId.isEmpty()) {
                userId = httpUserId;
            }
            if (userId != null && !userId.isEmpty()) {
                kafkaHeaders.put("user-id", userId);
            }

            // Correlation ID from HTTP header
            if (correlationId != null && !correlationId.isEmpty()) {
                kafkaHeaders.put("correlation-id", correlationId);
            }

            // Source system from HTTP header
            if (sourceSystem != null && !sourceSystem.isEmpty()) {
                kafkaHeaders.put("source-system", sourceSystem);
            }

            // Add custom metadata from request body
            if (eventRequest.getCustomMetadata() != null) {
                eventRequest.getCustomMetadata().forEach((key, value) -> {
                    if (key != null && value != null) {
                        kafkaHeaders.put("custom-" + key, value);
                    }
                });
            }

            // Determine the message key
            String messageKey = eventRequest.getKey();
            if (messageKey == null || messageKey.isEmpty()) {
                messageKey = trackingId;
            }

            // Send to Kafka
            RecordMetadata metadata = kafkaEventProducer.sendEvent(
                    eventRequest.getTopic(),
                    messageKey,
                    eventRequest.getPayload(),
                    kafkaHeaders
            );

            response.setStatus("SUCCESS");
            response.setTrackingId(trackingId);
            response.setTopic(metadata.topic());
            response.setPartition(metadata.partition());
            response.setOffset(metadata.offset());
            response.setMessage("Event published successfully");

            return ResponseEntity.ok(response);

        } catch (ExecutionException | InterruptedException e) {
            Thread.currentThread().interrupt();
            response.setStatus("ERROR");
            response.setMessage("Failed to publish event: " + e.getMessage());
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(response);
        } catch (Exception e) {
            response.setStatus("ERROR");
            response.setMessage("Unexpected error: " + e.getMessage());
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(response);
        }
    }

    @PostMapping("/publish-batch")
    public ResponseEntity<Map<String, Object>> publishBatchEvents(
            @RequestBody List<EventRequest> eventRequests,
            @RequestHeader(value = "X-Tracking-Id", required = false) String batchTrackingId,
            @RequestHeader(value = "X-User-Id", required = false) String httpUserId,
            @RequestHeader(value = "X-Source-System", required = false) String sourceSystem) {

        Map<String, Object> batchResponse = new HashMap<>();
        String batchId = (batchTrackingId != null && !batchTrackingId.isEmpty())
                ? batchTrackingId : UUID.randomUUID().toString();

        java.util.List<EventResponse> results = new java.util.ArrayList<>();
        int successCount = 0;
        int failureCount = 0;

        for (int i = 0; i < eventRequests.size(); i++) {
            EventRequest request = eventRequests.get(i);
            EventResponse itemResponse = new EventResponse();

            try {
                if (request.getTopic() == null || request.getPayload() == null) {
                    itemResponse.setStatus("ERROR");
                    itemResponse.setMessage("Topic and payload are required for item " + i);
                    failureCount++;
                    results.add(itemResponse);
                    continue;
                }

                Map<String, String> kafkaHeaders = new HashMap<>();

                String trackingId = request.getTrackingId();
                if (trackingId == null || trackingId.isEmpty()) {
                    trackingId = batchId + "-" + i;
                }
                kafkaHeaders.put("tracking-id", trackingId);
                kafkaHeaders.put("batch-id", batchId);
                kafkaHeaders.put("batch-index", String.valueOf(i));
                kafkaHeaders.put("batch-size", String.valueOf(eventRequests.size()));

                String userId = request.getUserId();
                if (userId == null || userId.isEmpty()) {
                    userId = httpUserId;
                }
                if (userId != null && !userId.isEmpty()) {
                    kafkaHeaders.put("user-id", userId);
                }

                if (sourceSystem != null && !sourceSystem.isEmpty()) {
                    kafkaHeaders.put("source-system", sourceSystem);
                }

                if (request.getCustomMetadata() != null) {
                    request.getCustomMetadata().forEach((key, value) -> {
                        if (key != null && value != null) {
                            kafkaHeaders.put("custom-" + key, value);
                        }
                    });
                }

                String messageKey = request.getKey() != null ? request.getKey() : trackingId;

                RecordMetadata metadata = kafkaEventProducer.sendEvent(
                        request.getTopic(), messageKey, request.getPayload(), kafkaHeaders);

                itemResponse.setStatus("SUCCESS");
                itemResponse.setTrackingId(trackingId);
                itemResponse.setTopic(metadata.topic());
                itemResponse.setPartition(metadata.partition());
                itemResponse.setOffset(metadata.offset());
                itemResponse.setMessage("Event published successfully");
                successCount++;

            } catch (Exception e) {
                itemResponse.setStatus("ERROR");
                itemResponse.setMessage("Failed: " + e.getMessage());
                failureCount++;
            }

            results.add(itemResponse);
        }

        batchResponse.put("batchId", batchId);
        batchResponse.put("totalEvents", eventRequests.size());
        batchResponse.put("successCount", successCount);
        batchResponse.put("failureCount", failureCount);
        batchResponse.put("results", results);

        HttpStatus status = failureCount == 0 ? HttpStatus.OK :
                (successCount == 0 ? HttpStatus.INTERNAL_SERVER_ERROR : HttpStatus.MULTI_STATUS);

        return ResponseEntity.status(status).body(batchResponse);
    }

    @GetMapping("/health")
    public ResponseEntity<Map<String, String>> healthCheck() {
        Map<String, String> health = new HashMap<>();
        health.put("status", "UP");
        health.put("service", "event-tracking-producer");
        health.put("timestamp", String.valueOf(System.currentTimeMillis()));
        return ResponseEntity.ok(health);
    }
}